advanced.WithDialog:
// JavaScript
import '@maersk-global/mds-components-core/mc-dialog';
import '@maersk-global/mds-components-core/mc-button';
import '@maersk-global/mds-components-core/mc-toast';
import '@maersk-global/mds-components-core/mc-notification';

const toggleDialog = () => {
  const mcDialog: IMcDialog = document.body.querySelector('mc-dialog') as IMcDialog;
  mcDialog.open = true;
};
const toggleToast = () => {
  const toast = document.body.querySelector('mc-toast');
  toast.open = true;
};

const mcButtonOpenDialog = document.getElementById('openDialog') as HTMLButtonElement;
mcButtonOpenDialog.addEventListener('click', () => toggleDialog());

const mcButtonShowToast = document.getElementById('showToast') as HTMLButtonElement;
mcButtonShowToast.addEventListener('click', () => toggleToast());

// HTML
<mc-toast duration="5000" appearance="success">
  <mc-notification body="Toast body text"></mc-notification>
</mc-toast>
<mc-button id="openDialog">Open dialog</mc-button>
<mc-dialog heading="Heading" customstacking>
  <div class="mds-flex mds-flex-column mds-gap-400">
    <mc-button
      id="showToast"
      label="Click to show toast"
      appearance="neutral"
      variant="outlined"
    ></mc-button>
    <a href="https://designsystem.maersk.com" target="_blank" rel="noopener noreferrer">Design System</a>
  </div>
  <mc-button slot="primaryAction" dialogaction="ok" appearance="primary">Ok</mc-button>
  <mc-button slot="secondaryAction" dialogaction="cancel" appearance="neutral" variant="outlined"
    >Cancel</mc-button
  >
</mc-dialog>
